import math

class SegmentTree:
    def __init__(self, arr):
        self.n = len(arr)
        self.arr = arr  # Orijinal diziyi sakla
        self.tree = [0] * (4 * self.n)  # Segment ağacının boyutu genellikle 4*N
        self._build(1, 0, self.n - 1)

    def _build(self, node, start, end):
        if start == end:
            self.tree[node] = self.arr[start]
        else:
            mid = (start + end) // 2
            self._build(2 * node, start, mid)
            self._build(2 * node + 1, mid + 1, end)
            self.tree[node] = min(self.tree[2 * node], self.tree[2 * node + 1])

    def update(self, idx, val):
        if not (0 <= idx < self.n):
            raise IndexError("Index aralık dışında.")
        self.arr[idx] = val  # Orijinal diziyi de güncelle
        self._update(1, 0, self.n - 1, idx, val)

    def _update(self, node, start, end, idx, val):
        if start == end:
            self.tree[node] = val
        else:
            mid = (start + end) // 2
            if start <= idx <= mid:
                self._update(2 * node, start, mid, idx, val)
            else:
                self._update(2 * node + 1, mid + 1, end, idx, val)
            self.tree[node] = min(self.tree[2 * node], self.tree[2 * node + 1])

    def query(self, l, r):
        if not (0 <= l <= r < self.n):
            raise IndexError("Sorgu aralığı dizinin dışında.")
        return self._query(1, 0, self.n - 1, l, r)

    def _query(self, node, start, end, l, r):
        # Durum 1: Düğümün temsil ettiği aralık, sorgu aralığının tamamen dışında
        if r < start or end < l:
            return math.inf  # Sonsuz değer döndür, minimumu etkilemeyecek

        # Durum 2: Düğümün temsil ettiği aralık, sorgu aralığının tamamen içinde
        if l <= start and end <= r:
            return self.tree[node]

        # Durum 3: Düğümün temsil ettiği aralık, sorgu aralığının kısmen içinde
        mid = (start + end) // 2
        p1 = self._query(2 * node, start, mid, l, r)
        p2 = self._query(2 * node + 1, mid + 1, end, l, r)
        return min(p1, p2)
